#!/usr/bin/env python3
"""
Bug #0066: OnnxRuntime graph optimizer produces wrong output.

Patterns : [['constant', 'where_const_cond'], ['branch', 'rrelu_inference_identity'], ['constant', 'pad_slice_noop'], ['layout', 'slice_step2_tile'], ['constant', 'redundant_reshape'], ['layout', 'resize_nearest_ceil']]
Divergence: rel L2 ≈ ~0.00e+00  (ORT_ENABLE_ALL vs pytorch_eager)

Dependencies: numpy onnx onnxruntime torch onnx2torch
Run: python unique_0066.py
"""
import os, sys
import numpy as np
import onnx, onnxruntime as ort
import torch, onnx2torch

MODEL = os.path.join(os.path.dirname(os.path.abspath(__file__)), "unique_0066.onnx")
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 3, 32, 32])


def reference():
    """pytorch eager — ground truth."""
    m = onnx2torch.convert(onnx.load(MODEL)).eval()
    with torch.no_grad():
        return m(torch.from_numpy(INPUT)).numpy().ravel()


def target():
    """OnnxRuntime with full graph optimisation."""
    opts = ort.SessionOptions()
    opts.graph_optimization_level = ort.GraphOptimizationLevel.ORT_ENABLE_ALL
    sess = ort.InferenceSession(MODEL, opts, providers=["CPUExecutionProvider"])
    return sess.run(None, {"model_input": INPUT})[0].ravel()


if __name__ == "__main__":
    ref = reference()
    out = target()
    diff = float(np.linalg.norm(ref.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(ref.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {ref[:6]}")
    print(f"actual   (ORT_ENABLE_ALL): {out[:6]}")
    print(f"rel L2: {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
